package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JavaVersionTest {

  private String originalJavaVersion;

  @BeforeEach
  public void setUp() {
    originalJavaVersion = System.getProperty("java.version");
  }

  @AfterEach
  public void tearDown() {
    if (originalJavaVersion != null) {
      System.setProperty("java.version", originalJavaVersion);
    } else {
      System.clearProperty("java.version");
    }
  }

  @Test
  public void testDetermineMajorJavaVersion_with_1_8() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    System.setProperty("java.version", "1.8.0_271");
    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);
    assertEquals(8, majorVersion);
  }

  @Test
  public void testDetermineMajorJavaVersion_with_11() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    System.setProperty("java.version", "11.0.9");
    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);
    assertEquals(11, majorVersion);
  }

  @Test
  public void testDetermineMajorJavaVersion_with_9() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    System.setProperty("java.version", "9");
    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);
    assertEquals(9, majorVersion);
  }

  @Test
  public void testDetermineMajorJavaVersion_with_17_0_1() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    System.setProperty("java.version", "17.0.1");
    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);
    assertEquals(17, majorVersion);
  }

  @Test
  public void testDetermineMajorJavaVersion_with_invalid_version() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    System.setProperty("java.version", "invalid.version.string");
    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int majorVersion = (int) method.invoke(null);
    // Assuming fallback behavior is 0 or some default, adjust if known differently
    assertEquals(0, majorVersion);
  }
}
